import java.math.BigInteger;

public class Main {
    private final static BigInteger MOD = new BigInteger("1000000007");

    public static BigInteger waysToCollide(int n) {
        BigInteger powerOf2 = BigInteger.ONE.shiftLeft(n).mod(MOD);
        return powerOf2.subtract(BigInteger.valueOf(n)).subtract(BigInteger.ONE).add(MOD).mod(MOD);
    }
}
```

